SELECT * FROM ( SELECT a.*, ROWNUM AS rn FROM ( SELECT NOTICE_ID AS noticeId, TITLE AS title, CONTENT AS content, VIEW_COUNT AS viewCount, PINNED_YN AS pinnedYn, POPUP_YN AS popupYn, POPUP_START_AT AS popupStartAt, POPUP_END_AT AS popupEndAt, STATUS AS status, CREATED_AT AS createdAt, UPDATED_AT AS updatedAt, END_DATE AS endDate FROM TBL_NOTICE
AND (TITLE LIKE '%'||#{search}||'%' OR CONTENT LIKE '%'||#{search}||'%')
ORDER BY PINNED_YN DESC, CREATED_AT DESC ) a WHERE ROWNUM <= #{offset} + #{limit} ) WHERE rn > #{offset}

mapper.insert:

  SELECT SEQ_NOTICE.NEXTVAL FROM DUAL

INSERT INTO TBL_NOTICE (
    NOTICE_ID, TITLE, CONTENT, PINNED_YN,
    POPUP_YN, POPUP_START_AT, POPUP_END_AT, STATUS, END_DATE
) VALUES (
    #{noticeId}, #{title}, #{content}, #{pinnedYn},
    #{popupYn}, #{popupStartAt, jdbcType=DATE}, #{popupEndAt, jdbcType=DATE},
    #{status}, #{endDate, jdbcType=DATE}
)

mapper.update:
UPDATE TBL_NOTICE
SET PINNED_YN = CASE WHEN PINNED_YN = 'Y' THEN 'N' ELSE 'Y' END
WHERE NOTICE_ID = #{noticeId}

UPDATE TBL_NOTICE
SET POPUP_YN = CASE WHEN NOTICE_ID = #{noticeId, jdbcType=NUMERIC} THEN 'Y' ELSE 'N' END
WHERE POPUP_YN = 'Y' OR NOTICE_ID = #{noticeId, jdbcType=NUMERIC}

mapper.select:
SELECT * FROM ( SELECT a.*, ROWNUM AS rn FROM ( SELECT NOTICE_ID AS noticeId, TITLE AS title, CONTENT AS content, VIEW_COUNT AS viewCount, PINNED_YN AS pinnedYn, CREATED_AT AS createdAt, END_DATE AS endDate FROM TBL_NOTICE WHERE STATUS = 1
AND (TITLE LIKE '%'||#{search}||'%' OR CONTENT LIKE '%'||#{search}||'%')
ORDER BY PINNED_YN DESC, CREATED_AT DESC ) a WHERE ROWNUM <= #{offset} + #{limit} ) WHERE rn > #{offset}
